import anthropic

client = anthropic.Anthropic()

def generate_requirements(pr_diff: str) -> str:
    message = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=2048,
        messages=[
            {
                "role": "user",
                "content": f"다음 PR diff를 분석해 요구사항 정의서를 작성하세요:\n\n{pr_diff}"
            }
        ]
    )
    return message.content[0].text
